'use client';

import { ReactNode, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useStore } from '@/store/useStore';
import { SkeletonCard } from '@/components/ui/Skeleton';

export function AuthGate({ children }: { children: ReactNode }) {
  const router = useRouter();
  const { accessToken, authReady } = useStore();

  useEffect(() => {
    if (!authReady) return;
    if (!accessToken) router.replace('/');
  }, [authReady, accessToken, router]);

  if (!authReady) {
    return (
      <div className="p-8 max-w-6xl mx-auto">
        <div className="mb-8">
          <div className="h-7 w-40 bg-slate-200 dark:bg-slate-700 rounded animate-pulse mb-2" />
          <div className="h-4 w-56 bg-slate-200 dark:bg-slate-700 rounded animate-pulse" />
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
          {Array.from({ length: 4 }).map((_, i) => (
            <SkeletonCard key={i} />
          ))}
        </div>
      </div>
    );
  }

  if (!accessToken) return null;
  return <>{children}</>;
}
